custom_css.gtk4:
:disabled {
color: alpha(mix(@error_color, @window_fg_color, 0.4), .7);
}



window.csd {
  box-shadow: 0 3px 12px 1px @headerbar_shade_color, 0 0 0 1px shade(@headerbar_shade_color,1.3);
}

window.csd:backdrop {
  box-shadow: 0 3px 12px 1px transparent, 0 2px 6px 2px rgba(0, 0, 0, 0.4), 0 0 0 1px shade(@headerbar_shade_color,1.1);
}

tiled, window.tiled-top, window.tiled-bottom, window.tiled-right, window.tiled-left decoration {
  box-shadow: 0 0 0 1px shade(@headerbar_shade_color,1.1), 0 0 0 20px transparent;
}

messagedialog.csd decoration, .csd.popup decoration, .maximized .csd.popup decoration {
  box-shadow: 0 1px 2px @headerbar_shade_color, 0 0 0 1px alpha(shade(@headerbar_shade_color,1.3),0.9);
}

.maximized .csd.popup decoration {
  border-radius: 6px;
}

.maximized decoration, .fullscreen decoration {
  border-radius: 0;
  box-shadow: none;
}

.ssd decoration {
  box-shadow: 0 0 0 1px shade(@headerbar_shade_color,1.3);
}

.ssd decoration:backdrop {
  box-shadow: 0 0 0 1px shade(@headerbar_shade_color,1.1);
}

.ssd.maximized decoration, .ssd.maximized decoration:backdrop {
  box-shadow: none;
}

.solid-csd decoration {
  box-shadow: inset 0 0 0 5px alpha(currentColor,0.5), inset 0 0 0 4px @headerbar_bg_color, inset 0 0 0 1px alpha(currentColor,0.5);
}

.solid-csd decoration:backdrop {
  box-shadow: inset 0 0 0 3px @window_bg_color;
}

.titlebar, headerbar {
  border-bottom-color: alpha(currentColor,0.15);
}

.titlebar:backdrop, headerbar:backdrop {
  border-bottom-color: alpha(currentColor,0.2);
}

popover > contents, popover > arrow, toast {
box-shadow: 0 0px 6px 1px @headerbar_shade_color;
border: 1px solid shade(@headerbar_shade_color,1.3);
}




button:hover {
	box-shadow: 0 0 .2em currentColor;
}

button:active, button:checked, slider:hover,
tab.reorderable-page:checked {
	box-shadow: inset 0 0 .2em currentColor;
}

button:active:hover, button:checked:hover {
	box-shadow: inset 0 0 .2em currentColor,
			0 0 .2em currentColor;
}

button:active > label,
button:checked > label,
button:active > image,
button:checked > image,
row:active > label,
row:active,
row:checked,
row:selected,
card:active label,
tab:selected *,
tab:checked * {
  text-shadow: 0 0 0.7em currentColor;
  -gtk-icon-shadow: 0 0 0.7em currentColor;
}

switch slider {
background-color: mix(@view_fg_color, @view_bg_color, 0.5);
color: @view_fg_color;
}
switch:checked slider {
background-color: @accent_fg_color;
color:@accent_color;
}

switch:disabled slider, switch:checked:disabled slider {
background-color: alpha(mix(@error_color, @window_fg_color, 0.4), 1);
}

switch:disabled {
opacity: 0.5;
}

button.titlebutton,
windowcontrols > button {
  min-width: 1.3em;
  min-height: 1.3em;
}

button.titlebutton:backdrop {
  opacity: 0.5;
}

windowcontrols > button {
  border-radius: 100%;
  padding: 0;
  margin: 0 5px;
}


windowcontrols > button > image {
  padding: 0;
}

button.titlebutton.close, button.titlebutton.close:hover:backdrop,
windowcontrols > button.close,
windowcontrols > button.close:hover:backdrop {
  background-color: @destructive_bg_color;
  color: @destructive_fg_color;

}

button.titlebutton.close:hover,
windowcontrols > button.close:hover {
  background-color: shade(@destructive_bg_color,1.3);
}

button.titlebutton.maximize, button.titlebutton.maximize:hover:backdrop,
windowcontrols > button.maximize,
windowcontrols > button.maximize:hover:backdrop {
  background-color: @success_bg_color;
  color: @success_fg_color;
}


button.titlebutton.maximize:hover,
windowcontrols > button.maximize:hover {
  background-color: shade(@success_bg_color,1.3);
}

button.titlebutton.minimize, button.titlebutton.minimize:hover:backdrop,
windowcontrols > button.minimize,
windowcontrols > button.minimize:hover:backdrop {
  background-color: @warning_bg_color;
  color: @warning_fg_color;
}

button.titlebutton.minimize:hover,
windowcontrols > button.minimize:hover {
  background-color: shade(@warning_bg_color,1.3);
}





notebook > header tab:not(:backdrop):checked.reorderable-page,
tabbar tab:not(:backdrop):checked {
  background-color: @headerbar_bg_color;
}




.nautilus-window .sidebar {
  background-color: @view_bg_color;
}

.nautilus-window .sidebar:backdrop {
  background-color: @window_bg_color;
}

.sidebar-pane {
background-color: mix(@view_bg_color, @window_bg_color, 0.5);
color: mix(@view_fg_color, @window_fg_color, 0.5);
}


label.error {
color: @error_color;
}

label.warning {
color: @warning_color;
}

label.success {
color: @success_color;
}

label.destructive, label.destructive-action {
color: @success_color;
}



undershoot {
background-image: image(alpha(@success_bg_color, 0.3));
background-repeat: no-repeat;
}

undershoot.top {
		background-size: 100% 0.5rem;
		background-position: top;
	}
undershoot.bottom {
		background-size: 100% 0.5rem;
		background-position: bottom;
	}
undershoot.left {
		background-size: 0.5rem 100%;
		background-position: left;	
	}
undershoot.right {
		background-size: 0.5rem 100%;
		background-position: right;	
	}

overshoot {
    background-image: radial-gradient(circle closest-side, @error_color, alpha(@error_color, 0));
    background-repeat: no-repeat;
}
overshoot.top {
    background-size: 100% 50%;
    background-position: top;
}
overshoot.bottom {
    background-size: 100% 50%;
    background-position: bottom;
}
overshoot.left {
    background-size: 50% 100%;
    background-position: left;
}
overshoot.right {
    background-size: 50% 100%;
    background-position: right;
}

